// ==========================================================================
// AUPE Agendador - Instagram Business Login
// Publishes a scheduled_posts row to Instagram via graph.instagram.com
// (the Instagram Business Login flow - distinct from Facebook Login).
//
// Input (from Supabase webhook via n8n Webhook node):
//   The n8n Webhook node wraps the incoming HTTP request as
//     { headers, params, query, body, webhookUrl, executionMode }
//   so the Supabase payload lives at `.body.*`. We tolerate both shapes
//   (wrapped + unwrapped) for robustness / manual testing.
//   Supabase payload shape:
//     { type, table, record: { ...scheduled_posts row..., client_data: {...} } }
//
// Output: { scheduled_post_id, status, instagram_post_id?, posted_at?, error_message?, last_retry_at? }
// ==========================================================================

const raw     = $input.first().json || {};
const payload = raw.body && typeof raw.body === 'object' ? raw.body : raw;
const record  = payload?.record || {};
const client  = record?.client_data || {};

const igUserId    = client.instagram_account_id;
const accessToken = client.access_token;
const GRAPH       = 'https://graph.instagram.com/v21.0';

// Capture the HTTP helper once — inside nested functions `this` would not
// refer to the n8n execution context anymore.
const httpRequest = this.helpers.httpRequest.bind(this.helpers);

function isTransient(errBody) {
  try {
    const e = JSON.parse(errBody)?.error;
    if (e?.is_transient === true) return true;
    if ([1, 2, 4, 17, 341, 368].includes(e?.code)) return true;
  } catch { /* not JSON */ }
  return false;
}

// n8n's Code-node sandbox does not expose URLSearchParams (and fetch can
// also be restricted on some installations), so we encode form data by hand
// and rely on `this.helpers.httpRequest` which is always available.
function encodeForm(params) {
  const parts = [];
  for (const k of Object.keys(params)) {
    const v = params[k];
    if (v === undefined || v === null) continue;
    parts.push(encodeURIComponent(k) + '=' + encodeURIComponent(String(v)));
  }
  return parts.join('&');
}

async function graphCall(method, path, params = {}) {
  let lastErr = '';
  for (let attempt = 1; attempt <= 4; attempt += 1) {
    const qs = encodeForm(params);
    let url = `${GRAPH}${path}`;
    const reqOpts = {
      method,
      url,
      returnFullResponse: true,
      ignoreHttpStatusErrors: true,
    };
    if (method === 'GET') {
      reqOpts.url = qs ? `${url}?${qs}` : url;
    } else {
      reqOpts.headers = { 'Content-Type': 'application/x-www-form-urlencoded' };
      reqOpts.body = qs;
    }
    let res;
    try {
      res = await httpRequest(reqOpts);
    } catch (e) {
      lastErr = String(e?.message || e);
      if (attempt < 4) {
        await new Promise(r => setTimeout(r, 2000 * Math.pow(2, attempt - 1)));
        continue;
      }
      break;
    }
    const statusCode = res.statusCode || res.status || 0;
    const bodyText = typeof res.body === 'string'
      ? res.body
      : (res.body ? JSON.stringify(res.body) : '');
    if (statusCode >= 200 && statusCode < 300) {
      try { return JSON.parse(bodyText); } catch { return res.body; }
    }
    lastErr = bodyText || `HTTP ${statusCode}`;
    if (attempt < 4 && isTransient(bodyText)) {
      await new Promise(r => setTimeout(r, 2000 * Math.pow(2, attempt - 1)));
      continue;
    }
    break;
  }
  throw new Error(`Graph API ${method} ${path} failed: ${lastErr.slice(0, 400)}`);
}

function extractImageUrls(images) {
  if (!Array.isArray(images)) return [];
  return images
    .map(img => (typeof img === 'string' ? img : img?.url || null))
    .filter(Boolean);
}

// Poll the container's status_code until Instagram reports FINISHED.
// Needed for ALL post types (including single image and carousel) —
// otherwise /media_publish can fail with code 9007 "Media ID is not available".
async function waitForContainerReady(creationId, { maxPolls, intervalMs }) {
  for (let i = 0; i < maxPolls; i += 1) {
    const s = await graphCall('GET', `/${creationId}`, {
      fields: 'status_code,status',
      access_token: accessToken,
    });
    if (s.status_code === 'FINISHED') return;
    if (s.status_code === 'ERROR' || s.status_code === 'EXPIRED') {
      throw new Error(`Container ${creationId} returned status ${s.status_code}: ${s.status || ''}`);
    }
    await new Promise(r => setTimeout(r, intervalMs));
  }
  throw new Error(`Container ${creationId} not FINISHED after ${maxPolls} polls`);
}

const scheduledPostId = record.id;
const postType        = String(record.post_type || 'post').toLowerCase();
const caption         = record.caption || '';
const imageUrls       = extractImageUrls(record.images);
const videoUrl        = record.video || null;
const shareToFeed     = record.share_to_feed !== false;

async function publish() {
  if (!igUserId || !accessToken) {
    throw new Error('Missing instagram_account_id or access_token in client_data');
  }

  let creationId;

  // -------- Reels flow ----------------------------------------------------
  if (postType === 'reels' || (videoUrl && imageUrls.length === 0)) {
    if (!videoUrl) throw new Error('Reels post requires a video URL');

    const created = await graphCall('POST', `/${igUserId}/media`, {
      media_type: 'REELS',
      video_url: videoUrl,
      share_to_feed: String(shareToFeed),
      caption,
      access_token: accessToken,
    });
    creationId = created.id;
    // Reels processing can take up to ~5 minutes.
    await waitForContainerReady(creationId, { maxPolls: 75, intervalMs: 4000 });

  // -------- Carousel flow (multiple images) -------------------------------
  } else if (imageUrls.length > 1) {
    const childIds = [];
    for (const url of imageUrls) {
      const child = await graphCall('POST', `/${igUserId}/media`, {
        image_url: url,
        is_carousel_item: 'true',
        access_token: accessToken,
      });
      // Wait for each child to be ready before assembling the carousel,
      // otherwise the parent container fails to publish.
      await waitForContainerReady(child.id, { maxPolls: 20, intervalMs: 2000 });
      childIds.push(child.id);
    }
    const created = await graphCall('POST', `/${igUserId}/media`, {
      media_type: 'CAROUSEL',
      children: childIds.join(','),
      caption,
      access_token: accessToken,
    });
    creationId = created.id;
    await waitForContainerReady(creationId, { maxPolls: 20, intervalMs: 2000 });

  // -------- Single image flow --------------------------------------------
  } else {
    if (imageUrls.length === 0) throw new Error('Photo post requires at least one image');
    const created = await graphCall('POST', `/${igUserId}/media`, {
      image_url: imageUrls[0],
      caption,
      access_token: accessToken,
    });
    creationId = created.id;
    // Even for single images, IG may need a second or two before the
    // container is publishable — otherwise we get code 9007
    // "Media ID is not available".
    await waitForContainerReady(creationId, { maxPolls: 20, intervalMs: 2000 });
  }

  const published = await graphCall('POST', `/${igUserId}/media_publish`, {
    creation_id: creationId,
    access_token: accessToken,
  });

  return published.id;
}

try {
  const instagramPostId = await publish();
  return [{
    json: {
      scheduled_post_id: scheduledPostId,
      status: 'posted',
      instagram_post_id: instagramPostId,
      posted_at: new Date().toISOString(),
    }
  }];
} catch (err) {
  return [{
    json: {
      scheduled_post_id: scheduledPostId,
      status: 'failed',
      error_message: String(err?.message || err).slice(0, 800),
      last_retry_at: new Date().toISOString(),
    }
  }];
}
